import{_ as e,c as i,o as l,ag as t}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"获取 API Key","description":"","frontmatter":{},"headers":[],"relativePath":"guide/get-api-key.md","filePath":"guide/get-api-key.md","lastUpdated":null}'),r={name:"guide/get-api-key.md"};function o(n,a,s,d,h,x){return l(),i("div",null,[...a[0]||(a[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\get-api-key.md for this page in Markdown format</div><h1 id="获取-api-key" tabindex="-1">获取 API Key <a class="header-anchor" href="#获取-api-key" aria-label="Permalink to &quot;获取 API Key&quot;">​</a></h1><p>本指南介绍如何注册账号并获取 Lurus API Key。</p><h2 id="注册账号" tabindex="-1">注册账号 <a class="header-anchor" href="#注册账号" aria-label="Permalink to &quot;注册账号&quot;">​</a></h2><ol><li>访问 <a href="https://api.lurus.cn" target="_blank" rel="noreferrer">Lurus 控制台</a></li><li>点击「注册」按钮</li><li>填写邮箱和密码</li><li>完成邮箱验证</li></ol><h2 id="创建-api-key" tabindex="-1">创建 API Key <a class="header-anchor" href="#创建-api-key" aria-label="Permalink to &quot;创建 API Key&quot;">​</a></h2><ol><li>登录控制台</li><li>点击左侧菜单「令牌管理」</li><li>点击「创建新令牌」按钮</li><li>填写令牌名称（便于识别用途）</li><li>点击确认创建</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>创建后请立即复制保存 API Key，它只会显示一次！</p></div><h2 id="api-key-格式" tabindex="-1">API Key 格式 <a class="header-anchor" href="#api-key-格式" aria-label="Permalink to &quot;API Key 格式&quot;">​</a></h2><p>Lurus API Key 以 <code>sk-</code> 开头，由 48 位随机字符组成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><h2 id="管理-api-key" tabindex="-1">管理 API Key <a class="header-anchor" href="#管理-api-key" aria-label="Permalink to &quot;管理 API Key&quot;">​</a></h2><h3 id="查看用量" tabindex="-1">查看用量 <a class="header-anchor" href="#查看用量" aria-label="Permalink to &quot;查看用量&quot;">​</a></h3><p>在「令牌管理」页面可以看到每个 Key 的：</p><ul><li>已用额度</li><li>剩余额度</li><li>最近调用时间</li></ul><h3 id="禁用-删除" tabindex="-1">禁用/删除 <a class="header-anchor" href="#禁用-删除" aria-label="Permalink to &quot;禁用/删除&quot;">​</a></h3><ul><li><strong>禁用</strong>: 暂时停止 Key 的使用权限，可以随时恢复</li><li><strong>删除</strong>: 永久删除 Key，无法恢复</li></ul><h3 id="设置模型权限" tabindex="-1">设置模型权限 <a class="header-anchor" href="#设置模型权限" aria-label="Permalink to &quot;设置模型权限&quot;">​</a></h3><p>可以限制 Key 只能访问特定模型：</p><ol><li>点击 Key 旁的「编辑」</li><li>在「可用模型」中选择允许的模型</li><li>保存设置</li></ol><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><ol><li><strong>不要泄露</strong>: 不要将 Key 提交到公开代码仓库</li><li><strong>定期轮换</strong>: 建议每 90 天更换一次 Key</li><li><strong>最小权限</strong>: 只授予 Key 必需的模型权限</li><li><strong>监控用量</strong>: 定期检查调用日志，发现异常及时处理</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-忘记了-api-key-怎么办" tabindex="-1">Q: 忘记了 API Key 怎么办？ <a class="header-anchor" href="#q-忘记了-api-key-怎么办" aria-label="Permalink to &quot;Q: 忘记了 API Key 怎么办？&quot;">​</a></h3><p>API Key 无法找回，请创建一个新的 Key。</p><h3 id="q-key-被盗用了怎么办" tabindex="-1">Q: Key 被盗用了怎么办？ <a class="header-anchor" href="#q-key-被盗用了怎么办" aria-label="Permalink to &quot;Q: Key 被盗用了怎么办？&quot;">​</a></h3><p>立即禁用或删除该 Key，并创建新的 Key。</p><h3 id="q-额度用完了怎么办" tabindex="-1">Q: 额度用完了怎么办？ <a class="header-anchor" href="#q-额度用完了怎么办" aria-label="Permalink to &quot;Q: 额度用完了怎么办？&quot;">​</a></h3><p>联系管理员充值或升级套餐。</p>',29)])])}const c=e(r,[["render",o]]);export{u as __pageData,c as default};
